func taskMoney(amount decimal.Decimal, currency string) string {
	if currency == "" {
		return Money(amount)
	}
	return Money(amount) + " " + currency
}

func taskStatusBadgeClass(status models.TaskStatus) string {
	base := "inline-block rounded px-2 py-0.5 text-small font-medium "
	switch status {
	case models.TaskStatusOpen:
		return base + "bg-primary-soft text-primary border border-primary-soft"
	case models.TaskStatusCompleted:
		return base + "bg-success-soft text-success-hover border border-success-border"
	case models.TaskStatusCancelled:
		return base + "bg-background text-text-muted2 border border-border line-through"
	case models.TaskStatusInvoiced:
		return base + "bg-warning-soft text-warning border border-warning-soft"
	default:
		return base + "bg-background text-text-muted border border-border"
	}
}

func taskCanEditLink(status models.TaskStatus) bool {
	return status == models.TaskStatusOpen || status == models.TaskStatusCompleted
}

